class SegmentTree {
  constructor(nums) {
    this.n=nums.length;
    this.tree=new Array(4*this.n).fill(0);
    this._build(nums,1,0,this.n-1);
  }
  _build(a,node,lo,hi) {
    if(lo===hi){this.tree[node]=a[lo];return;}
    const mid=(lo+hi)>>1;
    this._build(a,2*node,lo,mid);
    this._build(a,2*node+1,mid+1,hi);
    this.tree[node]=this.tree[2*node]+this.tree[2*node+1];
  }
  update(i,val,node=1,lo=0,hi=this.n-1) {
    if(lo===hi){this.tree[node]=val;return;}
    const mid=(lo+hi)>>1;
    if(i<=mid) this.update(i,val,2*node,lo,mid);
    else this.update(i,val,2*node+1,mid+1,hi);
    this.tree[node]=this.tree[2*node]+this.tree[2*node+1];
  }
  query(l,r,node=1,lo=0,hi=this.n-1) {
    if(r<lo||hi<l) return 0;
    if(l<=lo&&hi<=r) return this.tree[node];
    const mid=(lo+hi)>>1;
    return this.query(l,r,2*node,lo,mid)+this.query(l,r,2*node+1,mid+1,hi);
  }
}
